mapper.sql:
WHERE su.role_type = 2 AND COALESCE(mi.status, 1) = 1
AND (COALESCE(mi.store_name, su.real_name, su.username) LIKE CONCAT('%', #{keyword}, '%') OR mi.store_notice LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%') OR c.category_name LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id = #{categoryId}

mapper.select:
GROUP BY su.user_id, su.real_name, su.username, mi.store_name, mi.store_logo, mi.store_notice, mi.rating, mi.monthly_sales, mi.min_order_amount, mi.delivery_fee, mi.delivery_time, mi.distance_km, mi.status ORDER BY
monthlySales DESC, rating DESC, su.user_id DESC rating DESC, monthlySales DESC, su.user_id DESC distanceKm ASC, rating DESC, su.user_id DESC deliveryTime ASC, rating DESC, su.user_id DESC rating DESC, monthlySales DESC, distanceKm ASC, su.user_id DESC
LIMIT #{offset}, #{size}

mapper.sql:
WHERE p.status = 1
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%') OR c.category_name LIKE CONCAT('%', #{keyword}, '%') OR mi.store_name LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id = #{categoryId}
AND p.merchant_id = #{merchantId}

mapper.select:
ORDER BY
COALESCE(p.monthly_sales, p.order_count, 0) DESC, p.product_id DESC p.price ASC, p.product_id DESC p.price DESC, p.product_id DESC COALESCE(p.rating, 4.8) DESC, COALESCE(p.monthly_sales, p.order_count, 0) DESC, p.product_id DESC
LIMIT #{offset}, #{size}

mapper.update:
UPDATE product
SET stock = stock - #{quantity}
WHERE product_id = #{productId}
  AND status = 1
  AND stock >= #{quantity}

UPDATE product
SET order_count = COALESCE(order_count, 0) + #{quantity},
    monthly_sales = COALESCE(monthly_sales, 0) + #{quantity}
WHERE product_id = #{productId}
